                    <Grid item container xs={12}>
                        <Grid item xs={1}></Grid>
                        <Grid item xs={10}>
                            <div className="center">
                                <h1>Special Package</h1>
                            </div>
                        </Grid>
                        <Grid item xs={1}>
                            <div className="right">
                                <IconButton
                                    aria-label="delete"
                                    onClick={() => setOpen({ ...open, sp: false })}
                                >
                                    <Close />
                                </IconButton>
                            </div>
                        </Grid>
                        <Grid item md={2} lg={3} xl={4}></Grid>
                        <Grid item xs={12} className="center">
                            <MyTable
                                tTitle={"Special Package"}
                                tData={sp.data}
                                tColumns={columns_sp}
                            />
                        </Grid>
                    </Grid>
                </Grid>
            </Dialog>

        </div>
    )
}
